INSERT INTO tools (
  name, slug, tagline, description, website_url,
  pricing_type, pricing_details, skill_level, has_api, platforms,
  features, integrations, is_published,
  best_for, not_for, editorial_verdict,
  last_verified_at
) VALUES

-- ── reclaim-ai → productivity ────────────────────────────────
('Reclaim.ai', 'reclaim-ai', 'AI calendar autopilot — auto-schedules tasks, habits, focus time, and 1:1s into your existing Google or Outlook calendar.', 'Reclaim.ai is an AI calendar autopilot that auto-schedules tasks, habits, focus time, and 1:1s into the gaps in your existing Google or Outlook calendar. The product treats calendar slots as liquid: every event is moveable until locked, so the system can defend deep work blocks, slip flexible tasks into open time, and rebalance the schedule when something new comes in. Smart Meetings finds optimal times across attendees with calendar-aware availability. Scheduling Links surface 524% more bookable slots than competitors per Reclaim''s own benchmarks. Used by teams across engineering, sales, product, marketing, and finance. Competes with Motion (similar AI calendar, different UX), Akiflow (task-first), Clockwise (calendar-defragmentation focus), and Sunsama (planner with manual + AI hybrid).', 'https://reclaim.ai', 'freemium', '[{"plan":"Lite","price":"Free","features":["1 user","1-week scheduling range","Limited Focus Time","1 Scheduling Link","Limited integrations"]},{"plan":"Starter","price":"$10/seat/mo (annual) or $12/mo","features":["Up to 10 seats","8-week scheduling range","Unlimited Focus Time","3 Scheduling Links","3 organizer Smart Meetings","Unlimited integrations"]},{"plan":"Business","price":"$15/seat/mo (annual) or $18/mo","features":["Up to 100 seats","12-week scheduling range","Unlimited Scheduling Links","Unlimited Smart Meetings","OOO Calendar"]},{"plan":"Enterprise","price":"$22/seat/mo (annual only)","features":["100+ seats","SSO / SCIM","Dedicated support","Volume pricing"]}]'::jsonb, 'beginner', true, '{"web","mobile","plugin"}', '{"AI Focus Time — defend uninterrupted deep work blocks","AI Habits — recurring events that flex into optimal slots","AI Tasks — auto-schedule tasks by priority","AI Calendar Sync — block availability across multiple calendars","AI Buffer Time — auto-schedule breaks, prep, travel","AI Smart Meetings — optimal-time scheduling across attendees","AI Scheduling Links — 524%+ more openings vs competitors","Google + Outlook calendar support"}', '{"Google Calendar","Outlook Calendar","Slack","Zoom","Asana","ClickUp","Linear","Jira","Todoist","Google Tasks","Raycast"}', true, '{"Knowledge workers defending focus time on a meeting-heavy calendar","Engineering / product / sales teams scheduling 1:1s and Smart Meetings at scale","Outlook OR Google Calendar users (not Outlook-only or Google-only competitors)","Switchers from Motion or Calendly looking for calendar-first AI scheduling"}', '{"Pure project management — use Linear / Asana / Motion","Teams without Google or Outlook (no other calendar support)","Heavy SSO/SCIM enterprise needs at small scale (Enterprise tier $22/seat annual)","Solo users on Lite tier wanting Smart Meetings (capped at 0 organizer-led)"}', 'The cleanest pure-AI calendar autopilot for individual ICs and small teams who already live in Google Calendar or Outlook — Reclaim quietly defends focus time, slots tasks into open gaps, and finds meeting slots without the manual scheduling tax. It''s weaker than Motion on combined task-management UX, weaker than Akiflow on third-party-tool inbox unification, and the team tier ($15-22/seat) is steep for solo users. Pick Reclaim when you want calendar intelligence, not project management; pick Motion when you want both bundled.', now()),

-- ── token-metrics → research-education ──────────────────────
('Token Metrics', 'token-metrics', 'AI-powered crypto research and signals platform — daily market briefs synthesized from 41+ editorial and on-chain sources.', 'Token Metrics is an AI-powered cryptocurrency research platform that synthesizes data from 41+ editorial sources and 14+ on-chain feeds (CoinGecko, Nansen, DefiLlama, Polymarket, Bloomberg Crypto) into daily market briefs, real-time token signals, and portfolio-defense reports. The product is positioned for retail and prosumer crypto investors who want AI-generated narrative alongside raw data — not pure on-chain analytics. Distribution covers email, podcast, YouTube, Discord, and the $TMAI-token-gated platform. Read by 100,000+ investors with mentions in Bloomberg, CNBC, Forbes, Fortune, and CoinDesk. Competes with Messari (deeper editorial + raw data, no daily AI synthesis), Nansen (on-chain wallet analytics, no narrative), Glassnode (on-chain metrics specialist), and IntoTheBlock (institutional analytics with AI signals).', 'https://www.tokenmetrics.com', 'freemium', '[]'::jsonb, 'intermediate', false, '{"web"}', '{"Daily AI market brief synthesizing 41+ editorial sources","Real-time token-market and prediction-market signals","Market snapshots — BTC dominance, ETF flows, macro risk","Portfolio defense reports (Premium tier)","Multi-platform distribution — email / podcast / YouTube / Discord","Scenario-based intelligence framing (''watch this next'')","$TMAI token-gated platform access","Coverage of 41+ sources + 14+ on-chain data feeds"}', '{"CoinGecko","Nansen","DefiLlama","Polymarket","Bloomberg Crypto","CoinDesk","Gate.io","MEXC","Uniswap","Aerodrome"}', true, '{"Retail and prosumer crypto investors wanting daily AI-synthesized market briefs","Self-directed traders who want signals + narrative + risk reports in one platform","Crypto-native users comfortable with token-gated access ($TMAI)","Beginners overwhelmed by raw on-chain data who need editorial framing"}', '{"Institutional traders needing wallet-level on-chain forensics (use Nansen)","Fundamentals researchers needing deep editorial coverage (use Messari)","Quants needing programmatic data access (no widely-documented API)","Crypto-skeptical buyers uncomfortable with token-gated subscription mechanics"}', 'An AI-first crypto research platform for retail and prosumer investors who want a daily market narrative on top of the raw data Messari, Nansen, and Glassnode already provide. Token Metrics'' multi-source synthesis (41+ editorial, 14+ data feeds) is the differentiator; the daily brief is genuinely useful if you actually open it. It''s weaker than Nansen on wallet-level on-chain depth, weaker than Messari on editorial-research breadth, and the $TMAI-token gating model is friction for non-crypto-native buyers. Pick it when you want narrative AI synthesis; skip if you only need raw data feeds.', now()),

-- ── flowith → automation-agents ─────────────────────────────
('Flowith', 'flowith', 'Canvas-based AI workspace with multi-agent execution, infinite-context Agent Neo, and built-in image/video/website/slide generators.', 'Flowith is a canvas-based AI workspace that combines multi-agent execution (Agent Neo), a knowledge garden context system, and built-in generators for images, video, websites, and slides. The product''s distinguishing thesis is non-linear: instead of a chat thread, every task lives on a visual canvas where ideas, agents, and outputs connect spatially. Agent Neo handles long-running, multi-step tasks with claimed million-token context for sustained creation. Knowledge Garden serves as the persistent context layer across projects. Backed by OpenAI, Microsoft, AWS, NVIDIA Inception, and Google for Startups. Competes with Coze (similar agent canvas, ByteDance-backed), Lindy (more enterprise-workflow-focused), Dify (open-source), n8n (workflow-automation specialist), and Microsoft Copilot Studio (enterprise-incumbent).', 'https://www.flowith.io', 'freemium', '[]'::jsonb, 'intermediate', false, '{"web","desktop"}', '{"Canvas — collaborative visual workspace for ideas + agents","Agent Neo — multi-agent execution with million-token context","Knowledge Garden — persistent context system across projects","AI Image generation","AI Video animation","AI Website builder","AI Slides creation","FlowithOS — Mac desktop app"}', '{"OpenAI","Stripe","Microsoft","AWS","NVIDIA"}', true, '{"Visual thinkers and creators who prefer canvas over linear chat","Multi-modal workflows (image + video + slides + agent in one tool)","Long-running tasks needing extended context (Agent Neo''s million-token claim)","Designers and content creators consolidating off multiple single-purpose AI tools"}', '{"Teams wanting clear, public, predictable pricing","Enterprise buyers needing SSO / SCIM / audit logs (no enterprise tier disclosed)","Single-task automations (use n8n / Zapier / Make)","Workflows requiring deep marketplace of pre-built agents (Coze fits better)"}', 'An ambitious canvas-first AI workspace for creators who want spatial workflow over linear chat — Flowith bundles multi-agent execution (Agent Neo), generators for image/video/website/slides, and a Knowledge Garden context layer. The visual-canvas thesis is genuinely differentiated from chat-based agent tools. It''s weaker than Coze on agent-marketplace depth, weaker than Lindy on enterprise-workflow polish, and the no-public-pricing posture is friction for buyers wanting clear budget commitments. Pick Flowith if your work is visual / non-linear and you want one platform across multiple AI generators; skip it if a focused chat agent already covers the use case.', now()),

-- ── foxit → productivity ────────────────────────────────────
('Foxit', 'foxit', 'AI-powered PDF editor and document intelligence platform — the leading commercial alternative to Adobe Acrobat.', 'Foxit is the leading commercial alternative to Adobe Acrobat — PDF creation, editing, annotation, and e-signature with AI-driven document intelligence layered throughout. Foxit AI Assistant adds summarization, content rewriting, translation, key-data-point extraction, and an in-document chat interface; Foxit eSign handles legally-binding signatures. The desktop and web products integrate directly with Microsoft 365, Google Drive, Box, OneDrive, SharePoint, and Salesforce, with dedicated Salesforce automation flows for document workflows in CRM. Foxit positions explicitly as the cost-effective Adobe alternative, claiming the same feature surface at a lower price point and with a less aggressive subscription motion. Competes with Adobe Acrobat (incumbent), PDF Element (similar positioning), Smallpdf (browser-first lighter tool), and ilovepdf (free-tier-focused).', 'https://www.foxit.com', 'paid', '[]'::jsonb, 'beginner', false, '{"web","desktop","mobile"}', '{"PDF creation, editing, annotation","AI document summarization (long PDFs)","AI content rewriting and translation","AI key-data-point extraction","AI in-document chat interface","AI image insertion","Foxit eSign — legally-binding signatures","Microsoft 365 / Google Drive / Box / OneDrive / SharePoint integrations"}', '{"Microsoft 365","Google Drive","Box","OneDrive","SharePoint","Salesforce"}', true, '{"Teams replacing Adobe Acrobat to cut subscription costs without losing feature parity","Knowledge workers needing AI summarization + chat over long PDFs","Salesforce-using sales teams running document workflows in CRM","Microsoft 365 shops needing tight Office integration"}', '{"Hobbyist users with occasional PDF needs (use Smallpdf or ilovepdf free tiers)","Mac-first creative pros deeply invested in Adobe Creative Cloud workflows","Buyers wanting bundled e-sign + PDF in one SKU (Foxit splits these)","Workflows needing programmatic PDF generation (use a library like PDFKit)"}', 'The most credible commercial alternative to Adobe Acrobat in 2026 — Foxit''s PDF Editor matches Acrobat''s feature surface at materially lower cost, and the AI Assistant (summarization, chat, translation, data extraction) is competent if a step behind ChatGPT-direct. It''s weaker than Adobe on enterprise install base, weaker than Smallpdf on lightweight web-only workflows, and the multi-product split (Editor + AI Assistant + eSign as separate SKUs) confuses buyers. Pick Foxit when you need a real Acrobat alternative without the Adobe price; skip it for hobbyist-grade lightweight PDF tasks where Smallpdf wins.', now())

ON CONFLICT (slug) DO NOTHING;

-- Category links (one per tool — required for category filtering)
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'productivity'        WHERE t.slug = 'reclaim-ai'    ON CONFLICT DO NOTHING;
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'research-education'  WHERE t.slug = 'token-metrics' ON CONFLICT DO NOTHING;
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'automation-agents'   WHERE t.slug = 'flowith'       ON CONFLICT DO NOTHING;
INSERT INTO tool_categories (tool_id, category_id)
SELECT t.id, c.id FROM tools t JOIN categories c ON c.slug = 'productivity'        WHERE t.slug = 'foxit'         ON CONFLICT DO NOTHING;
